-- Rumbo a Ingeniería 2.0 — esquema inicial PostgreSQL/Supabase
create extension if not exists pgcrypto;
create type public.user_role as enum ('admin','teacher','student','parent');
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade, role public.user_role not null, full_name text not null, phone text, status text not null default 'active', created_at timestamptz not null default now());
create table public.parent_student(parent_id uuid references public.profiles(id) on delete cascade, student_id uuid references public.profiles(id) on delete cascade, primary key(parent_id,student_id));
create table public.courses(id uuid primary key default gen_random_uuid(), title text not null, subject text not null, level text, teacher_id uuid references public.profiles(id), status text default 'active', created_at timestamptz default now());
create table public.enrollments(course_id uuid references public.courses(id) on delete cascade, student_id uuid references public.profiles(id) on delete cascade, status text default 'active', primary key(course_id,student_id));
create table public.assignments(id uuid primary key default gen_random_uuid(), course_id uuid references public.courses(id) on delete cascade, title text not null, instructions text, due_at timestamptz, points numeric default 100, status text default 'draft', created_by uuid references public.profiles(id), created_at timestamptz default now());
create table public.submissions(id uuid primary key default gen_random_uuid(), assignment_id uuid references public.assignments(id) on delete cascade, student_id uuid references public.profiles(id) on delete cascade, answer text, file_url text, status text default 'submitted', score numeric, feedback text, submitted_at timestamptz default now(), graded_at timestamptz, unique(assignment_id,student_id));
create table public.classes(id uuid primary key default gen_random_uuid(), course_id uuid references public.courses(id) on delete cascade, teacher_id uuid references public.profiles(id), starts_at timestamptz not null, duration_minutes int default 60, status text default 'scheduled', meeting_url text, created_at timestamptz default now());
create table public.attendance(class_id uuid references public.classes(id) on delete cascade, student_id uuid references public.profiles(id) on delete cascade, status text default 'present', marked_at timestamptz default now(), primary key(class_id,student_id));
create table public.resources(id uuid primary key default gen_random_uuid(), title text not null, description text, subject text, level text, resource_type text, file_url text, external_url text, created_by uuid references public.profiles(id), created_at timestamptz default now());
create table public.messages(id uuid primary key default gen_random_uuid(), sender_id uuid references public.profiles(id), recipient_id uuid references public.profiles(id), body text not null, read_at timestamptz, created_at timestamptz default now());
create table public.payments(id uuid primary key default gen_random_uuid(), student_id uuid references public.profiles(id), concept text not null, amount numeric(10,2) not null, status text default 'pending', due_date date, paid_at timestamptz, created_at timestamptz default now());
create table public.notifications(id uuid primary key default gen_random_uuid(), user_id uuid references public.profiles(id) on delete cascade, title text not null, body text, read_at timestamptz, created_at timestamptz default now());
create table public.athena_conversations(id uuid primary key default gen_random_uuid(), user_id uuid references public.profiles(id) on delete cascade, prompt text not null, response text not null, created_at timestamptz default now());

alter table public.profiles enable row level security;alter table public.parent_student enable row level security;alter table public.courses enable row level security;alter table public.enrollments enable row level security;alter table public.assignments enable row level security;alter table public.submissions enable row level security;alter table public.classes enable row level security;alter table public.attendance enable row level security;alter table public.resources enable row level security;alter table public.messages enable row level security;alter table public.payments enable row level security;alter table public.notifications enable row level security;alter table public.athena_conversations enable row level security;
create or replace function public.my_role() returns public.user_role language sql stable security definer set search_path=public as $$select role from public.profiles where id=auth.uid()$$;
create policy "profile self or admin" on public.profiles for select using(id=auth.uid() or public.my_role()='admin');
create policy "admin manages profiles" on public.profiles for all using(public.my_role()='admin') with check(public.my_role()='admin');
create policy "courses visible by role" on public.courses for select using(public.my_role() in ('admin','teacher') or exists(select 1 from public.enrollments e where e.course_id=id and e.student_id=auth.uid()) or exists(select 1 from public.parent_student ps join public.enrollments e on e.student_id=ps.student_id where ps.parent_id=auth.uid() and e.course_id=id));
create policy "admin teacher manage courses" on public.courses for all using(public.my_role()='admin' or teacher_id=auth.uid()) with check(public.my_role()='admin' or teacher_id=auth.uid());
create policy "enrollment visibility" on public.enrollments for select using(public.my_role() in ('admin','teacher') or student_id=auth.uid() or exists(select 1 from public.parent_student ps where ps.parent_id=auth.uid() and ps.student_id=student_id));
create policy "admin manages enrollment" on public.enrollments for all using(public.my_role()='admin') with check(public.my_role()='admin');
create policy "assignments visible by course" on public.assignments for select using(exists(select 1 from public.courses c where c.id=course_id));
create policy "teachers manage assignments" on public.assignments for all using(public.my_role()='admin' or created_by=auth.uid()) with check(public.my_role()='admin' or created_by=auth.uid());
create policy "submissions visible" on public.submissions for select using(student_id=auth.uid() or public.my_role()='admin' or exists(select 1 from public.assignments a join public.courses c on c.id=a.course_id where a.id=assignment_id and c.teacher_id=auth.uid()) or exists(select 1 from public.parent_student ps where ps.parent_id=auth.uid() and ps.student_id=student_id));
create policy "student submits" on public.submissions for insert with check(student_id=auth.uid());
create policy "student updates own ungraded" on public.submissions for update using(student_id=auth.uid() and score is null);
create policy "teacher grades" on public.submissions for update using(public.my_role()='admin' or exists(select 1 from public.assignments a join public.courses c on c.id=a.course_id where a.id=assignment_id and c.teacher_id=auth.uid()));
create policy "messages participants" on public.messages for select using(sender_id=auth.uid() or recipient_id=auth.uid());
create policy "send message" on public.messages for insert with check(sender_id=auth.uid());
create policy "notifications own" on public.notifications for select using(user_id=auth.uid());
create policy "athena own" on public.athena_conversations for all using(user_id=auth.uid()) with check(user_id=auth.uid());
